  // ── Marché Hors Cote ──
  // ═══════════════════════════════════════════
  Future<List<InstrumentEntity>> getMarcheHorsCote() async {
    await Future.delayed(const Duration(milliseconds: 300));
    return const [
      InstrumentEntity(mnemo: 'SITEX', valeur: 'SITEX', statut: 'Closed', qteAchat: 0, achat: 0, vente: 0, qteVente: 2, dernier: 0, coursRef: 2.960, variation: 0, capitaux: 0, quantite: 0, nbTransactions: 0, ouverture: 0, plusHaut: 0, plusBas: 0, seuilHaut: 3.040, seuilBas: 2.880, market: InstrumentMarket.marcheHorsCote),
      InstrumentEntity(mnemo: 'STS', valeur: 'STE TUN. DU SUCRE', statut: 'Closed', qteAchat: 0, achat: 0, vente: 9.420, qteVente: 479, dernier: 0, coursRef: 9.410, variation: 0, capitaux: 0, quantite: 0, nbTransactions: 0, ouverture: 0, plusHaut: 0, plusBas: 0, seuilHaut: 9.690, seuilBas: 9.130, market: InstrumentMarket.marcheHorsCote),
    ];
  }

  /// Récupère les instruments par type de marché
  Future<List<InstrumentEntity>> getByMarket(InstrumentMarket market) {
    switch (market) {
      case InstrumentMarket.actions:
        return getActions();
      case InstrumentMarket.lignesSecondaires:
        return getLignesSecondaires();
      case InstrumentMarket.obligations:
        return getObligations();
      case InstrumentMarket.marcheHorsCote:
        return getMarcheHorsCote();
    }
  }

  /// Recherche dans un marché donné
  Future<List<InstrumentEntity>> searchInMarket(
    String query,
    InstrumentMarket market,
  ) async {
    final all = await getByMarket(market);
    final q = query.toLowerCase();
    return all
        .where((i) =>
            i.mnemo.toLowerCase().contains(q) ||
            i.valeur.toLowerCase().contains(q))
        .toList();
  }
